const express = require('express');
const session = require('express-session');
const axios = require('axios');
const jwt = require('jsonwebtoken');
const crypto = require('crypto');

const app = express();

// Configuration
const config = {
  clientId: process.env.CLIENT_ID || 'your-client-id',
  clientSecret: process.env.CLIENT_SECRET || 'your-client-secret',
  redirectUri: process.env.REDIRECT_URI || 'http://localhost:3000/callback',
  issuer: process.env.ISSUER || 'https://your-oidc-provider.com',
  authorizationEndpoint: process.env.AUTH_ENDPOINT || 'https://your-oidc-provider.com/authorize',
  tokenEndpoint: process.env.TOKEN_ENDPOINT || 'https://your-oidc-provider.com/token',
  jwksUri: process.env.JWKS_URI || 'https://your-oidc-provider.com/.well-known/jwks.json',
  scope: 'openid email profile'
};

// Session configuration
app.use(session({
  secret: process.env.SESSION_SECRET || crypto.randomBytes(32).toString('hex'),
  resave: false,
  saveUninitialized: false,
  cookie: {
    secure: process.env.NODE_ENV === 'production',
    httpOnly: true,
    maxAge: 24 * 60 * 60 * 1000,
    sameSite: 'lax'
  }
}));

app.use(express.json());
app.use(express.urlencoded({ extended: true }));

// JWKS cache
let jwksCache = null;
let jwksCacheTime = 0;
const JWKS_CACHE_DURATION = 3600000; // 1 hour

// Fetch JWKS
async function getJwks() {
  const now = Date.now();
  if (jwksCache && (now - jwksCacheTime) < JWKS_CACHE_DURATION) {
    return jwksCache;
  }
  
  const response = await axios.get(config.jwksUri);
  jwksCache = response.data;
  jwksCacheTime = now;
  return jwksCache;
}

// Convert JWK to PEM
function jwkToPem(jwk) {
  const key = crypto.createPublicKey({
    key: jwk,
    format: 'jwk'
  });
  return key.export({ type: 'spki', format: 'pem' });
}

// Get signing key
async function getSigningKey(kid) {
  const jwks = await getJwks();
  const key = jwks.keys.find(k => k.kid === kid);
  if (!key) {
    throw new Error('Unable to find matching key');
  }
  return jwkToPem(key);
}

// Verify and decode ID token
async function verifyIdToken(idToken) {
  const decodedHeader = jwt.decode(idToken, { complete: true });
  
  if (!decodedHeader) {
    throw new Error('Invalid token');
  }

  const kid = decodedHeader.header.kid;
  const publicKey = await getSigningKey(kid);

  const verified = jwt.verify(idToken, publicKey, {
    algorithms: ['RS256'],
    issuer: config.issuer,
    audience: config.clientId
  });

  // Validate nonce if present
  if (verified.nonce) {
    // Nonce validation would be done here against session
  }

  // Validate token expiration
  const now = Math.floor(Date.now() / 1000);
  if (verified.exp && verified.exp < now) {
    throw new Error('Token expired');
  }

  // Validate issued at time
  if (verified.iat && verified.iat > now + 300) {
    throw new Error('Token used before issued');
  }

  return verified;
}

// Middleware to check authentication
function requireAuth(req, res, next) {
  if (!req.session.user) {
    return res.redirect('/login');
  }
  next();
}

// Generate state and nonce
function generateRandomString() {
  return crypto.randomBytes(32).toString('hex');
}

// Home page
app.get('/', (req, res) => {
  if (req.session.user) {
    res.send(`
      <h1>Welcome, ${req.session.user.name || req.session.user.email}</h1>
      <p>Email: ${req.session.user.email}</p>
      <p>Subject: ${req.session.user.sub}</p>
      <a href="/profile">Profile</a> | <a href="/logout">Logout</a>
    `);
  } else {
    res.send('<h1>Home</h1><a href="/login">Login</a>');
  }
});

// Login endpoint
app.get('/login', (req, res) => {
  const state = generateRandomString();
  const nonce = generateRandomString();
  
  req.session.state = state;
  req.session.nonce = nonce;

  const authUrl = new URL(config.authorizationEndpoint);
  authUrl.searchParams.append('client_id', config.clientId);
  authUrl.searchParams.append('response_type', 'code');
  authUrl.searchParams.append('scope', config.scope);
  authUrl.searchParams.append('redirect_uri', config.redirectUri);
  authUrl.searchParams.append('state', state);
  authUrl.searchParams.append('nonce', nonce);

  res.redirect(authUrl.toString());
});

// Callback endpoint
app.get('/callback', async (req, res) => {
  const { code, state, error, error_description } = req.query;

  if (error) {
    return res.status(400).send(`Authentication error: ${error_description || error}`);
  }

  if (!code) {
    return res.status(400).send('No authorization code received');
  }

  // Verify state
  if (state !== req.session.state) {
    return res.status(400).send('Invalid state parameter');
  }

  try {
    // Exchange authorization code for tokens
    const tokenResponse = await axios.post(
      config.tokenEndpoint,
      new URLSearchParams({
        grant_type: 'authorization_code',
        code: code,
        redirect_uri: config.redirectUri,
        client_id: config.clientId,
        client_secret: config.clientSecret
      }),
      {
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded'
        }
      }
    );

    const { access_token, id_token, refresh_token } = tokenResponse.data;

    if (!id_token) {
      return res.status(400).send('No ID token received');
    }

    // Verify and decode ID token
    const claims = await verifyIdToken(id_token);

    // Verify nonce
    if (claims.nonce !== req.session.nonce) {
      return res.status(400).send('Invalid nonce');
    }

    // Extract user information from claims
    const user = {
      sub: claims.sub,
      email: claims.email,
      name: claims.name,
      given_name: claims.given_name,
      family_name: claims.family_name,
      picture: claims.picture,
      email_verified: claims.email_verified
    };

    // Create user session
    req.session.user = user;
    req.session.accessToken = access_token;
    req.session.idToken = id_token;
    if (refresh_token) {
      req.session.refreshToken = refresh_token;
    }

    // Clear state and nonce
    delete req.session.state;
    delete req.session.nonce;

    res.redirect('/');
  } catch (error) {
    console.error('Token exchange error:', error.response?.data || error.message);
    res.status(500).send('Authentication failed');
  }
});

// Profile endpoint
app.get('/profile', requireAuth, (req, res) => {
  res.json({
    user: req.session.user,
    message: 'This is a protected route'
  });
});

// Logout endpoint
app.get('/logout', (req, res) => {
  req.session.destroy((err) => {
    if (err) {
      console.error('Session destruction error:', err);
    }
    res.redirect('/');
  });
});

